select count(*) from postgres.comments as c, postgres.posts as p, postgres.votes as v, postgres.users as u where u.id = p.owneruserid and p.id = v.postid and p.id = c.postid and c.score=0 and c.creationdate<=timestamp '2014-09-10 02:47:53' and p.score>=0 and p.score<=19 and p.commentcount<=10 and p.creationdate<=timestamp '2014-08-28 13:31:33' and v.creationdate<=timestamp '2014-09-12 00:00:00' and u.downvotes>=0;
